#include <vector>
#include <algorithm>
#include <numeric>

using namespace std;

class UnionFind {
private:
    vector<int> parent;
    vector<int> size;
    int components;

public:
    UnionFind(int n) : parent(n), size(n, 1), components(n) {
        iota(parent.begin(), parent.end(), 0);
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX != rootY) {
            if (size[rootX] < size[rootY]) {
                swap(rootX, rootY);
            }
            parent[rootY] = rootX;
            size[rootX] += size[rootY];
            components--;
        }
    }

    int getComponents() const {
        return components;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    if (k <= 1) return 0;
    if (n < k) return -1; // Not possible, but per problem statement k <= n

    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    UnionFind uf(n);
    long long low = 0;
    long long high = 1e18;
    long long answer = 0;

    // Binary search for the minimal t
    while (low <= high) {
        long long mid = low + (high - low) / 2;
        UnionFind tempUF(n);
        for (const auto& edge : edges) {
            if (edge[2] > mid) {
                tempUF.unite(edge[0], edge[1]);
            }
        }
        if (tempUF.getComponents() >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

